-- Create "password_reset_tokens" table
CREATE TABLE "password_reset_tokens" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "user_id" bigint NOT NULL,
  "token_hash" character varying NOT NULL,
  "token_version" character varying NOT NULL DEFAULT 'v1',
  "expires_at" timestamptz NOT NULL,
  "used_at" timestamptz NULL,
  PRIMARY KEY ("id")
);
-- Create index "passwordresettoken_token_hash" to table: "password_reset_tokens"
CREATE UNIQUE INDEX "passwordresettoken_token_hash" ON "password_reset_tokens" ("token_hash");
-- Create index "passwordresettoken_user_id_created_at" to table: "password_reset_tokens"
CREATE INDEX "passwordresettoken_user_id_created_at" ON "password_reset_tokens" ("user_id", "created_at");
-- Create index "passwordresettoken_expires_at" to table: "password_reset_tokens"
CREATE INDEX "passwordresettoken_expires_at" ON "password_reset_tokens" ("expires_at");
-- Create index "passwordresettoken_used_at" to table: "password_reset_tokens"
CREATE INDEX "passwordresettoken_used_at" ON "password_reset_tokens" ("used_at");
